head.script:
//-------------------------------------------------------------------------
// 기본 날짜 세팅
//-------------------------------------------------------------------------
scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strFrDate = scwin.strCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)


scwin.pgmId       	= "fs_202_04_04b.jsp"; // 프로그램ID           
scwin.fmlaClsCd      	= "01"; // 서식구분코드            
scwin.fmlaPatternCd  	= "01"; // 서식유형코드 
scwin.bilglodeptNm = "";


//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

//공통코드데이터 호출   
const codeOptions = [
    { grpCd: "SD113", compID: "acb_odrKndCd" }, // 셀렉트
    { grpCd: "SD070", compID: "acb_taxnClsCd" } // 셀렉트
];

$c.data.setCommonCode(codeOptions);


};

//-------------------------------------------------------------------------
// 공통코드 완료시, onUdcCompleted보다 늦기 때문에 건너뛰고 해당 메소드사용
//-------------------------------------------------------------------------
scwin.ondataload = function() {
    $c.gus.cfDisableBtnOnly([btn_save]);
    // btn_save.setDisabled(true);
    rd_transCargoClsCd.setValue("C");
    rd_createClsCd.setValue("Order");
    // div_qryConKnd2.setStyle("display", "none");
    div_qryConKnd2.hide();
    ds_pgmid.insertRow();
    ds_pgmid.setCellData(0, "pgmId", "fs_202_04_01b.jsp");
    ds_pgmid.setCellData(0, "pgmNm", "수출입거래명세서");

    ds_pgmid.insertRow();
    ds_pgmid.setCellData(1, "pgmId","fs_202_04_06b.jsp");//ed_bilgLodeptCd.text;
    ds_pgmid.setCellData(1, "pgmNm", "내수거래명세서");    //ed_bilgLodeptCd.text;


}

//-------------------------------------------------------------------------
// 상세 서식구분 콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveDtlFmalPattern = function() {

    var p_bilgLodeptCd  = ed_bilgLodeptCd.getValue();
    var p_pgmId         = scwin.pgmId;
    var p_fmlaClsCd     = scwin.fmlaClsCd;

    dma_dtlfmlapattern.set("bilgLodeptCd", p_bilgLodeptCd);
    dma_dtlfmlapattern.set("pgmId", p_pgmId);
    dma_dtlfmlapattern.set("fmlaClsCd", p_fmlaClsCd);

    $c.sbm.execute(sbm_Dtlfmlapattern);

}

//-------------------------------------------------------------------------
// 조건 서식구분 콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveFmalPattern = function() {

    var p_bilgLodeptCd  = ed_bilgLodeptCd.getValue();
    var p_pgmId         = scwin.pgmId;
    var p_fmlaClsCd     = scwin.fmlaClsCd;

    dma_fmlapattern.set("bilgLodeptCd", p_bilgLodeptCd);
    dma_fmlapattern.set("pgmId", p_pgmId);
    dma_fmlapattern.set("fmlaClsCd", p_fmlaClsCd);

    $c.sbm.execute(sbm_fmlapattern);

}

//-------------------------------------------------------------------------
// 달력 UDC 기본 데이터 삽입 
//-------------------------------------------------------------------------
setTimeout (scwin.onUdcCompleted = function() {
    ica_qryConDt.setInitDate(scwin.strFrDate, scwin.strCurDate);
    ed_bilgLodeptCd.focus();
}, 150);

//-------------------------------------------------------------------------
// 조회조건 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onClick = async function (e) {
    await $c.gus.cfInitObjects(tbl_search);

    div_qryConKnd1.setStyle("display", "block");
    div_qryConKnd2.setStyle("display", "none");
    div_qryConKnd1.show();
    div_qryConKnd2.hide();

    btn_save.setDisabled(true);
    rd_transCargoClsCd.setValue("C");
    rd_createClsCd.setValue("Order");
    scwin.onUdcCompleted();


    // scwin.onpageload();
}



//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function() {
    //validation check        
    if(! await $c.gus.cfValidate([ed_bilgLodeptCd,ica_qryConDtFm,ica_qryConDtTo])){
        return;
    }



    dma_queryCondition.set("bilgLodeptCd", ed_bilgLodeptCd.getValue()); //"6A1";
    dma_queryCondition.set("qryDtConKnd", acb_qryDtConKnd.getValue());
    dma_queryCondition.set("qryConDtFm", ica_qryConDtFm.getValue());
    dma_queryCondition.set("qryConDtTo", ica_qryConDtTo.getValue());
    dma_queryCondition.set("qryConOdrNo", ed_qryConOdrNo.getValue());

    dma_queryCondition.set("taxnClsCd", acb_taxnClsCd.getValue());     	

    dma_queryCondition.set("bilgClntNo", ed_bilgClntNo.getValue());

    if(acb_odrKndCd.getValue() == "C1C3" || acb_odrKndCd.getValue() == "CSCT"){
        dma_queryCondition.set("odrKndCd1", acb_odrKndCd.getValue().substring(0,2));
        dma_queryCondition.set("odrKndCd2", acb_odrKndCd.getValue().substring(2));
    }else{
        dma_queryCondition.set("odrKndCd1", acb_odrKndCd.getValue());
        dma_queryCondition.set("odrKndCd2", acb_odrKndCd.getValue());  
    }

    dma_queryCondition.set("fmlaClsCd", scwin.fmlaClsCd);
    dma_queryCondition.set("fmlaPatternCd", acb_fmlaPatternCd.getValue());//"01";
    dma_queryCondition.set("impExpDomesticClsCd", acb_impExpDomesticClsCd.getValue());
    dma_queryCondition.set("transCargoClsCd", rd_transCargoClsCd.getValue());     
    dma_queryCondition.set("qryConKnd", acb_qryConKnd.getValue());     	 

    if(acb_qryConKnd.getValue() == "품명"){
        dma_queryCondition.set("sellCommNo", ed_qryConCd.getValue());
        dma_queryCondition.set("upperCommCd", "");	     	
        dma_queryCondition.set("kcgCd", "");	     		     	
    } else if(acb_qryConKnd.getValue() == "품목"){
        dma_queryCondition.set("sellCommNo", "");    	    	
        dma_queryCondition.set("upperCommCd", ed_qryConCd.getValue());
        dma_queryCondition.set("kcgCd", "");	     		     		     	    	
    } else if(acb_qryConKnd.getValue() == "화종"){
        dma_queryCondition.set("sellCommNo", "");    	    	
        dma_queryCondition.set("upperCommCd", "");
        dma_queryCondition.set("kcgCd", ed_qryConCd.getValue());
    }
    dma_queryCondition.set("createClsCd", rd_createClsCd.getValue());   

    $c.sbm.execute(sbm_retrieveCertiWholeCreationList);

}

//-------------------------------------------------------------------------
// 목록 조회 성공시
//-------------------------------------------------------------------------
scwin.sbm_retrieveCertiWhole_submitDone = function (e) {
    // 날짜열 데이터 조합
    for(i = 0; i < ds_certiCommon.getTotalRow(); i++) {
        let strDt = ds_certiCommon.getCellData(i, "qryConDtFm");
        let endDt = ds_certiCommon.getCellData(i, "qryConDtTo");
        let Dt = strDt + endDt;
        ds_certiCommon.setCellData(i, "Dt", Dt);

    }

};



