//-------------------------------------------------------------------------
// 저장 완료 후 데이터 로드 완료시
//-------------------------------------------------------------------------
scwin.ds_billingCommonMessage_ondataload = function () {
    let rowCnt = ds_billingCommonMessage.getTotalRow();

    if(rowCnt >= 1) {
        $c.win.alert(ds_billingCommonMessage.getCellData(0, "msg"))
    }


};



//-------------------------------------------------------------------------
// 일괄 저장 클릭시 / f_save()
//-------------------------------------------------------------------------
scwin.btn_save_onClick = async function (e) {
    if(ds_certiCommon.getTotalRow() < 1){ 
        $c.win.alert($c.data.getMessage(MSG_CM_WRN_003, "일괄저장할 통합매출 내역"));
        return;
    }

    let	transRow;
    let chkCnt = 0;

    if(ds_saveCertiCommon.getTotalRow() == 0) {
        // ds_saveCertiCommon.insertRow();
    } else {
        ds_saveCertiCommon.removeAll();
        ds_saveCertiCommon.setJSON([]);
    }


    for(i=0; i < ds_certiCommon.getTotalRow(); i++){
        if(ds_certiCommon.getCellData(i, "choice") == "T"){
            ds_saveCertiCommon.setCellData(i, "activePgmId","fs_202_04_04b.xml");
            ds_certiCommon.setCellData(i, "activePgmId", "fs_202_04_04b.xml");
            ds_saveCertiCommon.setCellData(i, "sellSeq", ds_certiCommon.getCellData(i, "sellSeq"));
            ds_certiCommon.setCellData(i, "sellSeq",ds_certiCommon.getCellData(i, "sellSeq"));

            if(ds_certiCommon.getCellData(i, "fmlaPatternCd") == null || ds_certiCommon.getCellData(i, "fmlaPatternCd") == ""){
                $c.win.alert("오더통합매출 내역의 "+(i+1)+"번째 데이터에 거래명세서유형은 필수입력 항목입니다.");
                return;
            }
            if(ds_certiCommon.getCellData(i, "confirmDt") == null || ds_certiCommon.getCellData(i, "confirmDt") == ""){
                $c.win.alert("오더통합매출 내역의 "+(i+1)+"번째 데이터에 확인일자 필수입력 항목입니다.");
                return;
            }

            transRow = ds_certiCommon.getRowArray(i);
            ds_saveCertiCommon.setRowArray(i, transRow, false)

            if(ds_saveCertiCommon.getCellData(i, "spplyAmt") == null || ds_saveCertiCommon.getCellData(i, "spplyAmt") == "" || ds_saveCertiCommon.getCellData(i, "spplyAmt") == isNaN) {
                ds_saveCertiCommon.setCellData(i, "spplyAmt", "0");
            }

            if(ds_saveCertiCommon.getCellData(i, "spplyAmtFcrc") == null || ds_saveCertiCommon.getCellData(i, "spplyAmtFcrc") == "" || ds_saveCertiCommon.getCellData(i, "spplyAmtFcrc") == isNaN) {
                ds_saveCertiCommon.setCellData(i, "spplyAmtFcrc", "0");
            }

            ds_saveCertiCommon.setCellData(chkCnt, "curRow", i);
            chkCnt++;
        }
    }

    if(chkCnt < 1){ 
        $c.win.alert($c.data.getMessage(MSG_CM_WRN_007,"저장할 자료"));
        return;
    }

    if(! await $c.win.confirm(MSG_CM_CRM_001)) {
        return;
    } 

    $c.sbm.execute(sbm_createCertiWhole);
};


//-------------------------------------------------------------------------
// 저장 완료시
//-------------------------------------------------------------------------
scwin.createCertiWhole_submitDone = function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) {
            $c.win.alert(e);
            return; //onFail

        }

    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }

};



//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};



//-------------------------------------------------------------------------
// UDC 공통 팝업 (청구부서)
//-------------------------------------------------------------------------
scwin.udc_bilgLodept_onClick = async function (e) {
    scwin.f_openCommonPopUp(1, ed_bilgLodeptCd.getValue(), ed_bilgLodeptNm.getValue(), 'F', 'F');

};

scwin.udc_bilgLodept_onblurCode = async function (e) {
    scwin.f_chkOpenCommonPopUp(ed_bilgLodeptCd, ed_bilgLodeptNm, 1);
};

scwin.udc_bilgLodept_onChangeName = async function (info) {
    scwin.f_chkOpenCommonPopUp(ed_bilgLodeptNm, ed_bilgLodeptCd, 1, false);
};

//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백(청구부서)
//-------------------------------------------------------------------------
scwin.udc_bilgLodept_callBackFunc = function(ret) {
    $c.gus.cfSetReturnValue(ret, ed_bilgLodeptCd, ed_bilgLodeptNm)

    if(ret != null && ret[0] != "N/A") {
        //거래명세서 유형 가져오기
        scwin.f_RetrieveFmalPattern();	
        //상세 거래명세서 유형 가져오기
        scwin.f_RetrieveDtlFmalPattern();	 
    }

    scwin.bilglodeptNm = ed_bilgLodeptNm.getValue();
}

//-------------------------------------------------------------------------
// UDC 공통 팝업 (청구처)
//-------------------------------------------------------------------------
scwin.udc_bilgClnt_onClick = async function (e) {
    scwin.f_openCommonPopUp(2, ed_bilgClntNo.getValue(), ed_bilgClntNm.getValue(), 'F', 'F')
};

scwin.udc_bilgClnt_onblurCode = async function (e) {
    scwin.f_chkOpenCommonPopUp(ed_bilgClntNo, ed_bilgClntNm, 2);
};

scwin.udc_bilgClnt_onChangeName = async function (info) {
    scwin.f_chkOpenCommonPopUp(ed_bilgClntNm, ed_bilgClntNo, 2, false);

};

//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백(청구처)
//-------------------------------------------------------------------------
scwin.udc_bilgClnt_callBackFunc = function(ret) {
        $c.gus.cfSetReturnValue(ret, ed_bilgClntNo, ed_bilgClntNm)
}

//-------------------------------------------------------------------------
// UDC 공통 팝업 (품목코드, 품명코드, 화종코드)
//-------------------------------------------------------------------------
scwin.udc_qryCon_onClick = async function (e) {
    scwin.f_beforeOpenCommonPopUp('img', ed_qryConCd, ed_qryConNm)
};

scwin.udc_qryCon_onblurCode = async function (e) {
	if(acb_qryConKnd.getValue() == "품목"){
		scwin.f_chkOpenCommonPopUp(ed_qryConCd, ed_qryConNm, 3);
	} else if(acb_qryConKnd.getValue() == "품명"){
		scwin.f_chkOpenCommonPopUp(ed_qryConCd, ed_qryConNm, 4);
	} else if(acb_qryConKnd.getValue() == "화종"){
		scwin.f_chkOpenCommonPopUp(ed_qryConCd, ed_qryConNm, 5);	
	}	
};

scwin.udc_qryCon_onChangeName = async function (info) {
    scwin.f_beforeOpenCommonPopUp('txt', ed_qryConCd, this)
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// 품목, 품명, 화종 코드 팝업 구분
//-------------------------------------------------------------------------
scwin.f_beforeOpenCommonPopUp = function(arg, cd, nm) {
    if(arg == "txt"){
        if(acb_qryConKnd.getValue() == "품목"){
            scwin.f_chkOpenCommonPopUp(nm, cd, 3, false);
        }else if(lc_qryConKnd.BindColVal == "품명"){
            scwin.f_chkOpenCommonPopUp(nm, cd, 4, false);
        }else{
            scwin.f_chkOpenCommonPopUp(nm, cd, 5, false);
        }
    }else{
        if(acb_qryConKnd.getValue() == "품목"){
            scwin.f_openCommonPopUp(3, cd.getValue(), nm.getValue(), 'F', 'F');
        }else if(acb_qryConKnd.getValue() == "품명"){
            scwin.f_openCommonPopUp(4, cd.getValue(), nm.getValue(), 'F', 'F');
        }else{
            scwin.f_openCommonPopUp(5, cd.getValue(), nm.getValue(), 'F', 'F');
        }
    }
}


//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면 

    switch (disGubun) {
        case 1:
            //청구부서코드팝업			
            udc_bilgLodept.cfCommonPopUp(
                scwin.udc_bilgLodept_callBackFunc
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,null);				


            break;		

        case 2:

            //청구화주코드팝업			
            udc_bilgClnt.cfCommonPopUp(
                scwin.udc_bilgClnt_callBackFunc
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,null);				 

            break;

        case 3:

            // 품목코드 팝업			
            udc_qryCon.setSelectId("retrieveCommInfo");

            udc_qryCon.cfCommonPopUp(
                scwin.udc_qryCon_callBackFunc
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,',,3'
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,'품목,품목코드,품목');	  				  			

            break;	

        case 4:

            udc_qryCon.setSelectId("retrieveCommInfo");
            // 품명코드 팝업			
            udc_qryCon.cfCommonPopUp(
                scwin.udc_qryCon_callBackFunc
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,',,4'
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,'품명,품명코드,품명');	  				  			

            break;

        case 5:
            udc_qryCon.setSelectId("retrieveKcgInfo");
            // 화종코드 팝업			
            udc_qryCon.cfCommonPopUp(
                scwin.udc_qryCon_callBackFunc
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,'1'
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,null);	  				  			

            break;									

        default:
            break;
    }
}	



