	    dma_orderselling_con.set("upperCommCd", ds_certiCommon.getCellData(row, "upperCommCd"));
	    dma_orderselling_con.set("blNo", "");
	    dma_orderselling_con.set("transDst", "");
	    dma_orderselling_con.set("onWrkPlCd", "");
	    dma_orderselling_con.set("offWrkPlCd", "");
     	dma_orderselling_con.set("prebilgYn", ds_certiCommon.getCellData(row, "prebilgYn"));
     	dma_orderselling_con.set("taxnClsCd", ds_certiCommon.getCellData(row, "taxnClsCd"));
     	dma_orderselling_con.set("transCargoClsCd", ds_certiCommon.getCellData(row, "transCargoClsCd"));
     	dma_orderselling_con.set("impExpDomesticClsCd", ds_certiCommon.getCellData(row, "impExpDomesticClsCd"));
     	dma_orderselling_con.set("dcsnClsCd", "");
     	dma_orderselling_con.set("lineCd", "");
     	dma_orderselling_con.set("vsslCd", "");
     	dma_orderselling_con.set("certiPatternCd", ds_certiCommon.getCellData(row, "certiPatternCd"));
     	dma_orderselling_con.set("receptClsCd", "");

	  	let pgm_id = ds_certiCommon.getCellData(row, "pgmId");

        dma_orderselling_con.set("pgmId", pgm_id);


        let args = {
            dma_orderselling_con : dma_orderselling_con.getJSON(),
