//-------------------------------------------------------------------------
// 건별조회 Cell 클릭시
//-------------------------------------------------------------------------
scwin.f_certiNoDetail = async function() {
    let row = gr_certiCommon.getFocusedRowIndex();
    let pgmId = ds_certiCommon.getCellData(row, "pgmId");  		
    if(pgmId == "fs_202_06_04p.jsp"){
        pgmId = "fs_202_04_01b.jsp";
    }


    pgmId = pgmId.replace(".jsp" , ".xml");


    let strCertiNoDetailUrl = "/ui/ds/fs/bilg/"+pgmId;


    // 선택된 certiNo 정보 : bilgLodeptCd , certiNo
    let v_bilgLodeptCd = ds_certiCommon.getCellData(row, "bilgLodeptCd");
    let v_certiNo      = ds_certiCommon.getCellData(row, "certiNo");  	
    let v_link         = "true";  	  		



    //팝업 옵션 설정
    let options = {
        id: "taxPop", 
        type: "",
        popupName: "",
        width:  1100,                   
        height: 650
    };




    //팝업 화면에 데이터 보내는 방법 1. json형태로 팝업화면에서 getParameter로 받기
    let args = {
        bilgLodeptCd: v_bilgLodeptCd,
        certiNo : v_certiNo,
        link : v_link
    };





    if(pgmId == "fs_202_04_01b.xml"){
        options.popupName = "수출입 거래명세서 작성";
    } else if(pgmId == "fs_202_04_03b.xml"){
        options.popupName = "기간매출 거래명세서 작성";						
    } else if(pgmId == "fs_202_04_06b.xml"){
        options.popupName = "내수 거래명세서 작성";			
    } else if(pgmId == "fs_202_05_01b.xml"){
        options.popupName = "컨테이너별 CERTI 생성";			
    } else if(pgmId == "fs_202_05_03b.xml"){
        options.popupName = "CERTI 생성";			
    } else if(pgmId == "fs_202_05_05b.xml"){
        options.popupName = "기간매출 CERTI 생성";			
    }	   


//menuNm, url, pgmId, paramObj, option
    //상세화면 호출
    $c.win.openMenu(options.popupName, strCertiNoDetailUrl, pgmId,args, options);
    return;
}



//-------------------------------------------------------------------------
// 신규 생성 클릭시 / f_Create
//-------------------------------------------------------------------------
scwin.btn_create_onClick = function (e) {
    ds_certiCommon.removeAll();
    ds_certidetail.removeAll();
    spa_totalRows.setValue("0");
    spa_totalRows2.setValue("0");
};

//-------------------------------------------------------------------------
// 상세 내역 조회시
//-------------------------------------------------------------------------
scwin.ds_certidetail_ondataload = function () {
    let rowCnt = ds_certidetail.getRowCount();

    spa_totalRows2.setValue(rowCnt);

    if(rowCnt == 0) {
        if(ds_certiCommon.getTotalRow() == 0) {
        return;   
        }
        spa_totalRows2.setValue(rowCnt);
        $c.win.alert(MSG_CM_WRN_002);
    } else {
        if (ds_certidetail.getCellData(0, "sellGoodsPatternCd") == "01"){
            gr_certidetail.setHeaderValue('commNmHd', "CNTR-NO");    
            gr_certidetail.setColumnVisible('unitCd', false);
        } else {
            gr_certidetail.setHeaderValue('commNmHd', "품명명");    
            gr_certidetail.setColumnVisible('unitCd', true);
        }	
    }

    gr_certidetail.setFocusedCell(0, 0);


};

//-------------------------------------------------------------------------
// 상단 그리드 데이터 조회시
//-------------------------------------------------------------------------
scwin.ds_certiCommon_ondataload = function () {
    let rowCnt = ds_certiCommon.getRowCount();

    if(ds_certiCommon.getTotalRow() >= 1) {
        $c.gus.cfEnableBtnOnly([btn_save]);
        // scwin.f_RetrieveUnitySell(0);
        spa_totalRows.setValue(ds_certiCommon.getTotalRow());
        spa_totalRows2.setValue(ds_certiCommon.getTotalRow());
    } else {
        $c.win.alert(MSG_CM_WRN_002);
        $c.gus.cfDisableBtnOnly([btn_save]);
        spa_totalRows.setValue(ds_certiCommon.getTotalRow());
        spa_totalRows2.setValue(ds_certiCommon.getTotalRow());

        // ds_certiCommon.setJSON([]);
        ds_certidetail.setJSON([]);

    }
    gr_certiCommon.setFocusedCell(0, 0);

};

scwin.ds_outCertiCommon_ondataload = function () {
    if(ds_outCertiCommon.getTotalRow() < 1) {
        $c.win.alert(MSG_CM_WRN_002)
    } else {
        // 그리드에 거래명세서 번호 SET
        for(i = 0; i < ds_outCertiCommon.getTotalRow(); i++) {
            ds_certiCommon.setCellData(ds_outCertiCommon.getCellData(i, "curRow"), "certiNo", ds_outCertiCommon.getCellData(i, "certiNo")); 
        }
        $c.gus.cfDisableBtnOnly([btn_save]);
    }
};


scwin.gr_certiDetail_custom = function(data, formattedData, rowIndex, colIndex) {
    let sell = ds_certidetail.getCellData(rowIndex, "sellSeq");

    return (data + "-" + sell);


}
